      'open-source.intro': 'The Pinfold mobile application (<code>com.pinfoldai.fileexplorer',
      'open-source.meta': 'Last updated: July 6, 2026 · Version 2026-07-06',
      'open-source.s1.p': 'Pinfold is grateful to the open source community. The Service is built using OSS libraries and frameworks maintained\n  by third parties under various open source licenses. Without these contributions, the Service would not be possible in\n  its current form.',
      'open-source.s1.title': '1. Acknowledgment',
      'open-source.s10.p': 'Open source licensing inquiries:\n  <a href="mailto:support@pinfoldai.com?subject=Open%20source%20inquiry">support@pinfoldai.com',
      'open-source.s10.title': '10. Contact',
